<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">CONTENT MANAGEMENT</span><h1><?=e($config['title'])?></h1></div><a class="btn" href="<?=url('admin/edit?module='.$module)?>">+ Add New</a></div><form class="admin-search" method="get"><input type="hidden" name="module" value="<?=e($module)?>"><input name="q" value="<?=e($q)?>" placeholder="Search records"><button class="btn outline">Search</button></form><div class="admin-panel"><div class="table-wrap"><table><thead><tr><?php foreach($config['list']as$f):?><th><?=e(ucwords(str_replace('_',' ',$f)))?></th><?php endforeach;?><th>Actions</th></tr></thead><tbody><?php foreach($rows as$row):?><tr><?php foreach($config['list']as$f):?><td><?php if(str_starts_with($f,'is_')||$f==='consent_recorded'):?><span class="status-pill <?=$row[$f]?'confirmed':'cancelled'?>"><?=$row[$f]?'Yes':'No'?></span><?php else:?><?=e(mb_strimwidth((string)($row[$f]??''),0,80,'…'))?><?php endif;?></td><?php endforeach;?><td><div class="table-actions"><a class="btn small outline" href="<?=url('admin/edit?module='.$module.'&id='.$row['id'])?>">Edit</a><form method="post" action="<?=url('admin/delete')?>" onsubmit="return confirm('Delete this record? Deactivation is safer for records already in use.')"><?=csrf_field()?><input type="hidden" name="module" value="<?=e($module)?>"><input type="hidden" name="id" value="<?=$row['id']?>"><button class="btn small danger">Delete</button></form></div></td></tr><?php endforeach;?></tbody></table></div><?php if(!$rows):?><div class="empty">No records found.</div><?php endif;?></div></div></section>

